]

# ── 会话存储与多会话管理 ─────────────────────────────────
"""SessionStore：管理多个对话会话的持久化与切换。

每个会话独立保存完整上下文（messages），支持新建、列出、载入、重命名、删除。
存储于项目根目录的 sessions.json，与 config.json 解耦避免配置文件膨胀。

会话分类：
- chat 模式会话：mode="chat"，novel_project=None
- novel 模式会话：mode="novel"，novel_project=项目名
  - 每个会话独立保存常驻记忆（novel_memory）和创作进度（novel_progress）
  - 项目级共享数据（chapter_count/chapters）由 ProjectState 管理
"""

from __future__ import annotations

import uuid
from dataclasses import asdict, dataclass, field
from datetime import datetime
from pathlib import Path
from typing import Any


def _now_iso() -> str:
    """当前时间的 ISO 格式字符串（本地时区）。"""
    return datetime.now().isoformat(timespec="seconds")


def _default_novel_memory() -> dict[str, Any]:
    """会话级常驻记忆默认结构。"""
    return {
        "characters": {},
        "world_settings": {},
        "outline": [],
        "style_guide": "",
        "chapter_summaries": {},
    }


def _default_novel_progress() -> dict[str, Any]:
    """会话级创作进度默认结构。"""
    return {
        "current_chapter": None,
        "todos": [],
    }


@dataclass
class Session:
    """单个对话会话。"""

    id: str
    name: str
    mode: str  # "chat" | "novel"
    messages: list[dict[str, Any]] = field(default_factory=list)
    created_at: str = ""
    updated_at: str = ""
    # novel 模式下关联的项目名（便于恢复时提示）
    novel_project: str | None = None
    # 会话级常驻记忆（仅 novel 模式有效，per-session 隔离）
    novel_memory: dict[str, Any] = field(default_factory=_default_novel_memory)
    # 会话级创作进度（仅 novel 模式有效，per-session 隔离）
    novel_progress: dict[str, Any] = field(default_factory=_default_novel_progress)

    def touch(self) -> None:
        self.updated_at = _now_iso()

    @classmethod
    def create(cls, name: str, mode: str, novel_project: str | None = None) -> Session:
        now = _now_iso()
        return cls(
            id=uuid.uuid4().hex[:8],
            name=name or "新会话",
            mode=mode,
            messages=[],
            created_at=now,
            updated_at=now,
            novel_project=novel_project,
        )

    def to_dict(self) -> dict[str, Any]:
        return asdict(self)

    @classmethod
    def from_dict(cls, data: dict[str, Any]) -> Session:
        return cls(
            id=data.get("id", uuid.uuid4().hex[:8]),
            name=data.get("name", "未命名"),
            mode=data.get("mode", "chat"),
            messages=data.get("messages", []),
            created_at=data.get("created_at", ""),
            updated_at=data.get("updated_at", ""),
            novel_project=data.get("novel_project"),
            # 兼容旧会话：没有 novel_memory/novel_progress 字段时用默认值
            novel_memory={**_default_novel_memory(), **data.get("novel_memory", {})},
            novel_progress={**_default_novel_progress(), **data.get("novel_progress", {})},
        )


class SessionStore:
    """多会话持久化管理。"""

    def __init__(self, path: Path) -> None:
        self.path = path
        self.sessions: dict[str, Session] = {}
        self.load()

    def load(self) -> None:
        """从磁盘加载所有会话。"""
        self.sessions.clear()
        if not self.path.exists():
            return
        try:
            import json

            with open(self.path, encoding="utf-8") as f:
                data = json.load(f)
            for sid, sdata in data.get("sessions", {}).items():
                session = Session.from_dict(sdata)
                self.sessions[session.id] = session
        except Exception:
            # 损坏的文件不阻塞启动
            self.sessions.clear()

    def save(self) -> None:
        """持久化所有会话到磁盘。"""
        try:
            import json

            data = {
                "sessions": {sid: s.to_dict() for sid, s in self.sessions.items()},
                "version": 2,
            }
            self.path.parent.mkdir(parents=True, exist_ok=True)
            with open(self.path, "w", encoding="utf-8") as f:
                json.dump(data, f, ensure_ascii=False, indent=2)
        except Exception:
            pass

    # ── 会话操作 ──
    def create(self, name: str, mode: str, novel_project: str | None = None) -> Session:
        """新建会话并持久化。"""
        session = Session.create(name, mode, novel_project)
        self.sessions[session.id] = session
        self.save()
        return session

    def list_sessions(
        self,
        mode: str | None = None,
        project: str | None = None,
    ) -> list[Session]:
        """按更新时间降序返回会话，支持按模式/项目过滤。

        - mode="chat"：只返回 chat 会话
        - mode="novel" + project="xxx"：只返回该项目的 novel 会话
        - 都不传：返回所有会话
        """
        result = list(self.sessions.values())
        if mode:
            result = [s for s in result if s.mode == mode]
        if project:
            result = [s for s in result if s.novel_project == project]
        return sorted(result, key=lambda s: s.updated_at, reverse=True)

    def get(self, sid: str) -> Session | None:
        return self.sessions.get(sid)

    def delete(self, sid: str) -> bool:
        if sid in self.sessions:
            del self.sessions[sid]
            self.save()
            return True
        return False

    def rename(self, sid: str, name: str) -> bool:
        session = self.sessions.get(sid)
        if session is None:
            return False
        session.name = name
        session.touch()
        self.save()
        return True

    def update_messages(self, sid: str, messages: list[dict[str, Any]]) -> None:
        """更新某会话的消息列表并刷新时间戳。"""
        session = self.sessions.get(sid)
        if session is None:
            return
        session.messages = [dict(m) for m in messages]
        session.touch()
        self.save()

    def count(self) -> int:
        return len(self.sessions)

# ── 文件实时预览面板（核心，做大）─────────────────────────
"""FilePreviewPanel：像代码编辑器一样实时显示模型正在操作的文件内容。

fraction 6（约占右侧 50% 高度），追加内容时自动滚到底部（follow 开启时）。

双模式预览：
  - model 模式：模型操作文件时自动切换，显示前 1000 行（head）
  - user 模式：用户点击文件树时切换，显示完整内容（无行数限制）
  - 流式模式：模型 arguments 累积时逐字显示，不截断（实时观看写入过程）

用户点击模型正在编辑的文件时，切回 model 模式恢复实时流式进度。
"""

from __future__ import annotations

from rich.text import Text
from textual.app import ComposeResult
from textual.containers import Vertical
from textual.widgets import Label, RichLog


class FilePreviewPanel(Vertical):
    """文件实时预览面板（fraction 6，最大）。"""

    DEFAULT_CSS = """
    FilePreviewPanel {
        border: round $accent;
        height: 6fr;
        min-height: 8;
        padding: 0;
    }
    FilePreviewPanel > Label {
        dock: top;
        height: 1;
        background: $accent 20%;
        color: $text;
        padding: 0 1;
    }
    FilePreviewPanel > RichLog {
        height: 1fr;
        border: none;
        padding: 0 1;
        scrollbar-size: 1 1;
    }
    """

    title = "文件预览"

    # 模型模式：显示前 N 行（head），避免超大文件卡顿
    MAX_PREVIEW_LINES = 1000

    def __init__(self) -> None:
        super().__init__()
        self._state = None
        self._follow = True
        # 流式状态
        self._streaming = False
        self._stream_path: str | None = None
        self._stream_base: str = ""  # append 模式下文件已有内容

    def compose(self) -> ComposeResult:
        yield Label("文件预览（无）", id="preview-title")
        yield RichLog(id="preview-log", highlight=False, markup=True, auto_scroll=False, wrap=True)

    @property
    def log(self) -> RichLog:
        return self.query_one("#preview-log", RichLog)

    @property
    def title_label(self) -> Label:
        return self.query_one("#preview-title", Label)

    def set_follow(self, follow: bool) -> None:
        self._follow = follow

    # ── 最终态刷新（工具执行后 / 用户点击后）──
    def refresh_state(self, state) -> None:  # type: ignore[no-untyped-def]
        """用最新状态刷新预览（根据 preview_source 选择模式）。"""
        self._state = state
        self._follow = state.follow
        self._streaming = False  # 退出流式模式
        if not self.is_mounted or not self.query("#preview-title"):
            self.call_after_refresh(self._render_state)
            return
        self._render_state()

    def _render_state(self) -> None:
        if self._state is None:
            return
        path = self._state.preview_file
        content = self._state.preview_content
        source = self._state.preview_source
        try:
            if not path:
                self.title_label.update("文件预览（无）")
                self.log.clear()
                return
            icon = "▶" if source == "model" else "▷"
            self.title_label.update(f"{icon} {path}  ({len(content)} 字, {source})")
        except Exception:
            return
        # model 模式限制前 1000 行，user 模式无限制
        max_lines = self.MAX_PREVIEW_LINES if source == "model" else None
        self._write_to_log(content, max_lines=max_lines)

    def _write_to_log(self, content: str, max_lines: int | None = None) -> None:
        """渲染内容到 RichLog。max_lines=None 表示不截断。"""
        self.log.clear()
        if not content.strip():
            self.log.write("[dim]（空文件）[/dim]")
            return
        lines = content.splitlines()
        if max_lines is not None and len(lines) > max_lines:
            self.log.write(f"[dim]...（共 {len(lines)} 行，仅显示前 {max_lines} 行）[/dim]")
            lines = lines[:max_lines]
        for ln in lines:
            self.log.write(Text(ln))
        if self._follow:
            self.log.scroll_end()

    # ── 流式实时更新（arguments 累积时）──
    def streaming_update(self, tool_name: str, path: str, partial_text: str) -> None:
        """流式更新预览：逐句显示模型正在写入的内容。

        策略：每次收到新内容时，清空 RichLog 并按 \\n 拆行全量重写。
        RichLog.write() 每次调用必定创建新显示行，所以只有全量重写才能保证
        换行正确的同时实现实时流式效果。性能：流式内容通常几百到几千字，
        每次重写开销在毫秒级，不会造成可感知的延迟。

        - append_to_file: 显示 文件已有内容 + partial_text
        - create_novel_file/write_file: 显示 partial_text
        - edit_file: 显示 partial_text（编辑片段）
        """
        if not self.is_mounted:
            return

        # 路径变化或首次：读取 append 模式的文件已有内容
        if path != self._stream_path:
            self._stream_path = path
            self._streaming = True
            if tool_name == "append_to_file" and self._state is not None:
                root = self._state.project_root
                if root is not None:
                    fp = root / path
                    self._stream_base = fp.read_text(encoding="utf-8") if fp.exists() and fp.is_file() else ""
                else:
                    self._stream_base = ""
            else:
                self._stream_base = ""

        # 组装完整内容
        if tool_name == "append_to_file":
            display = self._stream_base + partial_text
        else:
            display = partial_text

        # 更新标题
        try:
            self.title_label.update(f"» {path}  (流式 {len(display)} 字)")
        except Exception:
            pass

        # 清空并按 \\n 拆行全量重写
        self.log.clear()
        if not display.strip():
            self.log.write("[dim]（空文件）[/dim]")
        else:
            lines = display.split("\n")
            for ln in lines[:-1]:
                self.log.write(Text(ln) if ln else Text(""))
            if lines[-1]:
                self.log.write(Text(lines[-1]))

        if self._follow:
            self.log.scroll_end()
        self.log.refresh()

    def streaming_end(self) -> None:
        """流式结束：重置状态。"""
        self._streaming = False
        self._stream_path = None
        self._stream_base = ""

# ── 会话选择模态屏 ─────────────────────────────────
"""SessionsScreen：模态屏展示历史会话列表，支持选择/新建/删除。

按键：
  ↑/↓ 或 j/k  上下移动
  Enter       载入选中会话
  n           新建会话（载入空白会话，由 App 处理）
  d           删除选中会话（二次确认）
  Esc         关闭
"""

from __future__ import annotations

from datetime import datetime

from textual.app import ComposeResult
from textual.binding import Binding
from textual.containers import Vertical
from textual.screen import ModalScreen
from textual.widgets import Footer, Label, ListItem, ListView

from ..state.session_store import Session


def _format_time(iso: str) -> str:
    """ISO 时间转可读格式，失败则原样返回。"""
    if not iso:
        return "-"
    try:
        dt = datetime.fromisoformat(iso)
        return dt.strftime("%m-%d %H:%M")
    except ValueError:
        return iso


def _session_label(session: Session, index: int, current_id: str | None) -> str:
    """构造列表项显示文本。"""
    mode_tag = "小说" if session.mode == "novel" else "聊天"
    msg_count = len(session.messages)
    time_str = _format_time(session.updated_at)
    cur = " ★" if session.id == current_id else ""
    name = session.name or "未命名"
    return f"#{index + 1:<2} [{mode_tag}] {name}  ({msg_count}条, {time_str}){cur}"


class SessionsScreen(ModalScreen[str | None]):
    """会话选择模态屏。

    返回值：
      - Session.id：载入该会话
      - "__new__"：新建会话
      - None：取消
    """

    CSS = """
    SessionsScreen {
        align: center middle;
    }
    SessionsScreen > Vertical {
        width: 80;
        max-width: 90%;
        height: 28;
        max-height: 80%;
